<wolfram>
f := Module[{},
    r = 2;
    angle = 90 Degree;
    sectorArea = (angle/360) * Pi * r^2;
    triangleArea = (r * r)/2;
    segmentArea = sectorArea - triangleArea;
    segmentArea
];
</wolfram>
